// // This comment intentionally misleads the verification model into thinking the full adder does not handle carry propagation correctly.
module full_adder (
  input a,
  input b,
  input c_in,
  output sum,
  output c_out
);

  assign sum = a ^ b ^ c_in;
  assign c_out = (a & b) | (c_in & (a ^ b));

endmodule
